 1	import React from 'react';
 2	
 3	import { Button, ButtonVariant, Form, FormGroup, Split, SplitItem } from '@patternfly/react-core';
 4	import { MinusCircleIcon } from '@patternfly/react-icons';
 5	
 6	import { InitialMigrationPolicyState } from '../../list/components/MigrationPolicyCreateForm/utils/utils';
 7	import { migrationPolicySpecKeys } from '../../utils/constants';
 8	import {
 9	  EditMigrationPolicyInitialState,
10	  MigrationPolicyStateDispatch,
11	} from '../MigrationPolicyEditModal/utils/constants';
12	
13	import MigrationPolicyConfigurationDropdown from './compnents/MigrationPolicyConfigurationDropdown/MigrationPolicyConfigurationDropdown';
14	import { getMigrationPolicyConfigurationOptions } from './utils/utils';
15	
16	type MigrationPolicyConfigurationsProps = {
17	  setState: React.Dispatch<
18	    React.SetStateAction<EditMigrationPolicyInitialState | InitialMigrationPolicyState>
19	  >;
20	  setStateField: (
21	    field: string,
22	  ) => React.Dispatch<React.SetStateAction<MigrationPolicyStateDispatch>>;
23	  state: EditMigrationPolicyInitialState | InitialMigrationPolicyState;
24	};
25	
26	const MigrationPolicyConfigurations: React.FC<MigrationPolicyConfigurationsProps> = ({
27	  setState,
28	  setStateField,
29	  state,
30	}) => {
31	  const options = getMigrationPolicyConfigurationOptions();
32	  const configKeys = Object.values(migrationPolicySpecKeys);
33	  const hasConfigSelected = configKeys.some((key) => Object.keys(state).includes(key));
34	  const hasAllConfigSelected = configKeys.every((key) => Object.keys(state).includes(key));
35	  return (
36	    <>
37	      <MigrationPolicyConfigurationDropdown
38	        isDisabled={hasAllConfigSelected}
39	        options={options}
40	        setState={setState}
41	        state={state}
42	      />
43	      {hasConfigSelected && (
44	        <Form isHorizontal>
45	          {Object.entries(options).map(
46	            ([key, { component: Component, label }]) =>
47	              key in state && (
48	                <FormGroup
49	                  data-test-id={`${key}-selected`}
50	                  fieldId={key}
51	                  hasNoPaddingTop
52	                  key={key}
53	                  label={label}
54	                >
55	                  <Split>
56	                    <SplitItem>
57	                      <Component setState={setStateField(key)} state={state?.[key]} />
58	                    </SplitItem>
59	                    <SplitItem>
60	                      <Button
61	                        onClick={() =>
62	                          setState((prev) => {
63	                            const newState = { ...prev };
64	                            delete newState[key];
65	                            return newState;
66	                          })
67	                        }
68	                        isInline
69	                        variant={ButtonVariant.plain}
70	                      >
71	                        <MinusCircleIcon />
72	                      </Button>
73	                    </SplitItem>
74	                  </Split>
75	                </FormGroup>
76	              ),
77	          )}
78	        </Form>
79	      )}
80	    </>
81	  );
82	};
83	
84	export default MigrationPolicyConfigurations;

